import React, { useState } from 'react';
import { Document, Page, pdfjs } from 'react-pdf';
import 'react-pdf/dist/esm/Page/AnnotationLayer.css';
import 'react-pdf/dist/esm/Page/TextLayer.css';
import '../styles/ConsentFormViewer.css';

// PDF.js worker 설정
pdfjs.GlobalWorkerOptions.workerSrc = `//unpkg.com/pdfjs-dist@${pdfjs.version}/build/pdf.worker.min.js`;

const ConsentFormViewer = ({ isOpen, onClose }) => {
  const [numPages, setNumPages] = useState(null);
  const [pageNumber, setPageNumber] = useState(1);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [scale, setScale] = useState(1.0);

  const onDocumentLoadSuccess = ({ numPages }) => {
    setNumPages(numPages);
    setLoading(false);
    setError(null);
  };

  const onDocumentLoadError = (error) => {
    console.error('PDF 로딩 오류:', error);
    setError('PDF 파일을 불러올 수 없습니다.');
    setLoading(false);
  };

  const changePage = (offset) => {
    setPageNumber(prevPageNumber => prevPageNumber + offset);
  };

  const previousPage = () => changePage(-1);
  const nextPage = () => changePage(1);

  const zoomIn = () => setScale(prevScale => Math.min(prevScale + 0.2, 3.0));
  const zoomOut = () => setScale(prevScale => Math.max(prevScale - 0.2, 0.5));

  if (!isOpen) return null;

  return (
    <div className="consent-viewer-overlay">
      <div className="consent-viewer-modal">
        <div className="consent-viewer-header">
          <h3>📄 피험자동의서</h3>
          <div className="viewer-controls">
            <button onClick={zoomOut} disabled={scale <= 0.5} title="축소">
              🔍-
            </button>
            <span className="zoom-level">{Math.round(scale * 100)}%</span>
            <button onClick={zoomIn} disabled={scale >= 3.0} title="확대">
              🔍+
            </button>
            <button onClick={onClose} className="close-btn" title="닫기">
              ✕
            </button>
          </div>
        </div>

        <div className="consent-viewer-content">
          {loading && (
            <div className="loading-message">
              <p>📄 PDF 파일을 불러오는 중...</p>
            </div>
          )}

          {error && (
            <div className="error-message">
              <p>❌ {error}</p>
              <button onClick={onClose} className="btn">
                닫기
              </button>
            </div>
          )}

          {!loading && !error && (
            <>
              <div className="pdf-container">
                <Document
                  file={`${process.env.PUBLIC_URL || ''}/피험자동의서.pdf`}
                  onLoadSuccess={onDocumentLoadSuccess}
                  onLoadError={onDocumentLoadError}
                  loading={<div>PDF 로딩 중...</div>}
                >
                  <Page
                    pageNumber={pageNumber}
                    scale={scale}
                    renderAnnotationLayer={true}
                    renderTextLayer={true}
                  />
                </Document>
              </div>

              {numPages > 1 && (
                <div className="page-controls">
                  <button
                    onClick={previousPage}
                    disabled={pageNumber <= 1}
                    className="btn page-btn"
                  >
                    ← 이전
                  </button>
                  <span className="page-info">
                    {pageNumber} / {numPages}
                  </span>
                  <button
                    onClick={nextPage}
                    disabled={pageNumber >= numPages}
                    className="btn page-btn"
                  >
                    다음 →
                  </button>
                </div>
              )}
            </>
          )}
        </div>

        <div className="consent-viewer-footer">
          <p className="helper-text">
            💡 마우스 휠이나 터치로 스크롤하여 확대/축소할 수 있습니다.
          </p>
        </div>
      </div>
    </div>
  );
};

export default ConsentFormViewer; 